python3 -c "
import json
with open('/workspace/YatCC/build/test/task2/functional-0/001_var_defn.sysu.c/answer.json') as f:
    j = json.load(f)
# Find DeclRefExpr in inner items
def find_refs(obj, path=''):
    if isinstance(obj, dict):
        k = obj.get('kind','')
        if k == 'DeclRefExpr':
            print(f'{path}: {json.dumps(obj, indent=2)}')
            return
        if 'inner' in obj:
            for i, item in enumerate(obj['inner']):
                find_refs(item, f'{path}.inner[{i}]')
    elif isinstance(obj, list):
        for i, item in enumerate(obj):
            find_refs(item, f'{path}[{i}]')
find_refs(j)
"
